input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    S = sum(a)
    # dp[pos + S][left] = min right
    # pos in [-S, S], left in [0, S], right in [0, S]
    INF = float('inf')
    dp = {}
    dp[(0, 0)] = 0  # (pos, left) -> min_right
    for d in a:
        ndp = {}
        for (pos, left), right in dp.items():
            for npos in [pos + d, pos - d]:
                nleft = max(left, -npos)
                nright = max(right, npos)
                key = (npos, nleft)
                if key not in ndp or ndp[key] > nright:
                    ndp[key] = nright
        dp = ndp
    ans = INF
    for (pos, left), right in dp.items():
        ans = min(ans, left + right)
    print(ans)

t = int(input())
for _ in range(t):
    solve()

